import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).resolve().parents[1] / "src"))

from service import order_summary


def test_order_without_discount_still_formats_subtotal():
    order = {"items": [{"price": 4, "qty": 2}, {"price": 1}]}

    assert order_summary(order) == "$9"


def test_order_summary_applies_discount():
    order = {"items": [{"price": 10, "qty": 2}], "discount": 3}

    assert order_summary(order) == "$17"

from __future__ import annotations

from calculator import final_total
from formatter import format_total


def order_summary(order: dict) -> str:
    amount = final_total(order["items"], discount=order.get("discount", 0))
    return format_total(amount)

from __future__ import annotations


def subtotal(items: list[dict]) -> int:
    return sum(item["price"] * item.get("qty", 1) for item in items)


def final_total(items: list[dict], discount: int = 0) -> int:
    return subtotal(items) + discount

